#include <bits/stdc++.h>
using namespace std;

const int N=210;

int n,m,p;
int b[N],inv[N],cnt[N],mi[N],fac=1,ans=0;

void dfs(int x,int num,int res){
    if(!res){
        ans=(ans+num)%p;
        return;
    }
    for(int i=b[x-1];i<=res;i++){
        b[x]=i;
        cnt[i]++;
        int pr=1ll*inv[i]*inv[cnt[i]]%p*mi[i/2]%p;
        for(int j=1;j<x;j++)
            pr=1ll*pr*mi[__gcd(b[j],i)]%p;
        dfs(x+1,1ll*num*pr%p,res-i);
        cnt[i]--;
    }
}

int main(){
    scanf("%d%d%d",&n,&m,&p);
    inv[0]=inv[1]=1;
    for(int i=2;i<=n;i++){
        inv[i]=1ll*(p-p/i)*inv[p%i]%p;
        fac=1ll*fac*i%p;
    }
    mi[0]=1;
    for(int i=1;i<N;i++)
        mi[i]=1ll*mi[i-1]*m%p;
    b[0]=1;
    dfs(1,1,n);
    printf("%d",ans);
    return 0;
}
